func maxCoins(nums []int) int {
    n := len(nums)
    arr := make([]int, n+2)
    arr[0] = 1
    arr[n+1] = 1
    for i := 0; i < n; i++ { arr[i+1] = nums[i] }
    dp := make([][]int, n+2)
    for i := range dp {
        dp[i] = make([]int, n+2)
    }
    for length := 1; length <= n; length++ {
        for i := 1; i <= n-length+1; i++ {
            j := i + length - 1
            for k := i; k <= j; k++ {
                val := dp[i][k-1] + dp[k+1][j] + arr[i-1]*arr[k]*arr[j+1]
                if val > dp[i][j] { dp[i][j] = val }
            }
        }
    }
    return dp[1][n]
}

